    codePattern: "export function reverseString(s) {\n  const chars = s.split(\"\");\n  let left = 0, right = chars.length - 1;\n  while (left < right) {\n    [chars[left], chars[right]] = [chars[right], chars[left]];\n    left++; right--;\n  }\n  return chars.join(\"\");\n}",
