    codePattern: "class Node { constructor(v){ this.value=v; this.prev=this.next=null; } }\nexport class DoublyLinkedList {\n  constructor(){ this.head=this.tail=null; }\n  append(v){ const n=new Node(v); if(!this.tail){this.head=this.tail=n;} else { n.prev=this.tail; this.tail.next=n; this.tail=n; } }\n  remove(node){ if(node.prev) node.prev.next=node.next; else this.head=node.next; if(node.next) node.next.prev=node.prev; else this.tail=node.prev; }\n}",
    bigO: "insert/delete với node ref O(1), index access O(n). Space O(n) + extra prev pointers.",
